sourcesContent:
import { useEffect } from 'react';
import './App.css';

const PHOTO = 'data:image/png;base64,';

const SKILLS = [
  { icon:'☕', title:'Backend Development', cls:'v', chips:['Java','Spring Boot','Spring MVC','Hibernate/JPA','Microservices','REST APIs','J2EE','Servlets/JSP','Multithreading'] },
  { icon:'⚛️', title:'Frontend Development', cls:'c', chips:['React JS','JavaScript (ES6+)','HTML5','CSS3','Component Design','REST Integration'] },
  { icon:'🗄️', title:'Databases',           cls:'d', chips:['MySQL','MSSQL','Query Optimization','Schema Design','JDBC'] },
  { icon:'🛠️', title:'Tools & Practices',   cls:'t', chips:['Git','Maven','Jenkins','Postman','Jira','Agile/Scrum','OOP','Design Patterns','Creo API','Windchill API'] },
];

const STATS = [['2+','Years Exp.'],['3+','Projects Built'],['40%','Effort Cut'],['50+','Users Served']];

const INFO = [
  ['📍','Location','Bengaluru, India'],
  ['💼','Company','CADOPT Technologies Pvt Ltd'],
  ['✉️','Email','maheshdoddikalu@gmail.com'],
  ['📱','Phone','+91 9491825731'],
];

const EXP_METRICS = [['60%','Faster data turnaround'],['15+','Hours saved / week'],['10k+','Records managed']];

const EXP_POINTS = [
  'Designed & shipped 5+ RESTful APIs using Spring Boot — reduced inter-team data turnaround by 60%',
  'Built Design Automation tool in Java+Creo eliminating ~40% of manual CAD modeling effort',
  'Architected Spring Data JPA layers managing 10,000+ engineering records with optimized queries',
  'Delivered React JS dashboards replacing manual Excel workflows for 50+ internal users',
  'Built Windchill PLM integration auto-generating BOM-style assembly reports on demand',
  'Full Agile cycle: requirements → specs → unit tests → production debugging → 2-week sprints',
];

const TESTIMONIALS = [
  {
    avatar:'SK', name:'Senior Engineer', role:'CADOPT Technologies · Team Lead',
    text:'Mahesh built our CAD automation tool from scratch and it\'s now a core part of how our engineering team operates daily. What impressed me most was his ability to <strong>understand the domain problem</strong> and translate it into clean, maintainable Spring Boot code without hand-holding.',
  },
  {
    avatar:'PM', name:'Project Manager', role:'CADOPT Technologies · Engineering',
    text:'He delivered the Assembly Configurator Web App ahead of schedule and the quality was production-ready from day one. Engineers who previously fought with manual selection processes were using the app within hours. <strong>Rarely see this level of ownership from someone with 2 years of experience.</strong>',
  },
  {
    avatar:'RE', name:'CAD Engineer', role:'CADOPT Technologies · End User',
    text:'The Windchill reporting tool Mahesh built <strong>cut a 30+ minute manual process to under 2 minutes</strong>. Every engineer on the floor uses it now. He\'s the kind of developer who doesn\'t just write code — he solves the actual problem.',
  },
];

const CONTACTS = [
  ['✉️','Email','maheshdoddikalu@gmail.com','mailto:maheshdoddikalu@gmail.com'],
  ['in','LinkedIn','linkedin.com/in/doddikalu-mahesh','https://linkedin.com/in/doddikalu-mahesh-a4a527329'],
  ['⌥','GitHub','github.com/chandu180522','https://github.com/chandu180522'],
  ['📱','Phone','+91 9491825731','tel:9491825731'],
];

export default function App() {
  useEffect(() => {
    const canvas = document.getElementById('particles');
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    let W, H, rafId;
    const pts = Array.from({ length: 70 }, () => ({
      x:Math.random()*2000, y:Math.random()*1200,
      vx:(Math.random()-0.5)*0.3, vy:(Math.random()-0.5)*0.3,
      r:Math.random()*1.5+0.5, a:Math.random(),
    }));
    const resize = () => { W=canvas.width=window.innerWidth; H=canvas.height=window.innerHeight; };
    resize(); window.addEventListener('resize',resize);
    const draw = () => {
      ctx.clearRect(0,0,W,H);
      pts.forEach(p => {
        p.x+=p.vx; p.y+=p.vy;
        if(p.x<0)p.x=W; if(p.x>W)p.x=0;
        if(p.y<0)p.y=H; if(p.y>H)p.y=0;
        ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
        ctx.fillStyle=`rgba(108,99,255,${p.a*0.4})`; ctx.fill();
      });
      pts.forEach((a,i) => pts.slice(i+1).forEach(b => {
        const d=Math.hypot(a.x-b.x,a.y-b.y);
        if(d<120){ctx.beginPath();ctx.moveTo(a.x,a.y);ctx.lineTo(b.x,b.y);ctx.strokeStyle=`rgba(108,99,255,${(1-d/120)*0.12})`;ctx.stroke();}
      }));
      rafId=requestAnimationFrame(draw);
    };
    draw();
    return () => { cancelAnimationFrame(rafId); window.removeEventListener('resize',resize); };
  }, []);

  useEffect(() => {
    const io = new IntersectionObserver(entries =>
      entries.forEach(e => { if(e.isIntersecting) e.target.classList.add('visible'); }),
      { threshold:0.1 }
    );
    document.querySelectorAll('.fade-up').forEach(el => io.observe(el));
    return () => io.disconnect();
  }, []);

  return (
    <div>
      <canvas id="particles" />

      {/* NAV */}
      <nav>
        <div className="nav-logo">Mahesh.dev</div>
        <ul className="nav-links">
          {['about','skills','projects','experience','testimonials','contact'].map(s => (
            <li key={s}><a href={`#${s}`}>{s.charAt(0).toUpperCase()+s.slice(1)}</a></li>
          ))}
        </ul>
        <div className="nav-right">

          <a href="mailto:maheshdoddikalu@gmail.com" className="nav-hire">Hire Me</a>
        </div>
      </nav>

      {/* HERO */}
      <section className="hero" id="home">
        <div className="blob blob1"/><div className="blob blob2"/>
        <div className="hero-left">
          <div className="hero-greeting"><span>// Hello, World!</span><span className="blink">█</span></div>
          <h1>I'm <span className="grad">Mahesh</span><br/>Doddikalu.</h1>
          <div className="hero-subtitle"><span>Full Stack Developer</span> — Java · Spring Boot · React JS</div>
          <p className="hero-desc">
            2+ years shipping production features at <strong>CADOPT Technologies Pvt Ltd</strong>.
            I cut engineering manual work by <strong>40%</strong>, built APIs serving <strong>50+ users</strong>,
            and turned spreadsheets into <strong>live React dashboards</strong>.
          </p>
          <div className="hero-actions">
            <a href="#projects" className="btn-glow">View My Work</a>
            <a href="#contact" className="btn-border">Get In Touch</a>
            <a href="Mahesh_Doddikalu_Resume.pdf" download="Mahesh_Doddikalu_Resume.pdf" className="btn-resume-hero">⬇ Download Resume</a>
          </div>
          <div className="hero-stats">
            {STATS.map(([n,l]) => (
              <div key={l}><div className="hstat-num">{n}</div><div className="hstat-label">{l}</div></div>
            ))}
          </div>
        </div>
        <div className="hero-right">
          <div style={{position:'relative',display:'inline-block'}}>
            <div className="photo-ring photo-ring-1"/><div className="photo-ring photo-ring-2"/>
            <div className="photo-wrapper"><img src={PHOTO} alt="Mahesh Doddikalu"/></div>
            <div className="photo-badge">✦ Available for Work</div>
          </div>
          <div className="quick-links">
            <a href="mailto:maheshdoddikalu@gmail.com" className="quick-link">✉ Email</a>
            <a href="https://github.com/chandu180522" target="_blank" rel="noreferrer" className="quick-link">⌥ GitHub</a>
            <a href="https://linkedin.com/in/doddikalu-mahesh-a4a527329" target="_blank" rel="noreferrer" className="quick-link">in LinkedIn</a>
            <a href="tel:9491825731" className="quick-link">☎ Call</a>
          </div>
        </div>
      </section>

      {/* ABOUT */}
      <section className="about-section" id="about">
        <div className="sec-tag">about-me</div>
        <h2 className="sec-title">The Person <span className="hl">Behind the Code</span></h2>
        <div className="about-grid">
          <div className="fade-up">
            <p className="about-intro">I'm a developer who <strong>genuinely enjoys engineering problems</strong> — not just the code, but the moment a 30-minute manual process becomes a 2-minute button click.</p>
            <p className="about-story">I grew up in <strong>Andhra Pradesh</strong>, built my technical foundation at SV University, and leveled up through a hands-on Java Full Stack certification in Chennai. Since joining <strong>CADOPT Technologies</strong>, I've worked inside a real engineering SaaS product serving industrial teams — not tutorial apps.</p>
            <p className="about-story">Day-to-day, I own features from <strong>database schema → Spring Boot API → React UI</strong>. I've integrated Windchill PLM APIs, automated CAD workflows that engineers now use as their default tool, and built dashboards that replaced Excel chaos with live data.</p>
            <p className="about-story">Outside work I'm sharpening my skills in <strong>system design</strong> and contributing to open source. I'm looking for a team where I can grow fast, ship real things, and work with people who care about quality.</p>
            <div className="about-values">
              {['🚀 Ownership mindset','🔧 End-to-end builder','📐 Clean code advocate','⚡ Fast learner','🤝 Agile team player'].map(v=>(
                <span key={v} className="about-value">{v}</span>
              ))}
            </div>
          </div>
          <div className="fade-up">
            <div className="info-cards">
              {INFO.map(([icon,label,value])=>(
                <div className="info-card" key={label}>
                  <div className="info-icon">{icon}</div>
                  <div><div className="info-label">{label}</div><div className="info-value">{value}</div></div>
                </div>
              ))}
              <div className="info-card">
                <div className="info-icon">🟢</div>
                <div><div className="info-label">Status</div><div className="info-value" style={{color:'var(--accent3)'}}>Open to Opportunities</div></div>
              </div>
            </div>
            <a href="resume.pdf" download="Mahesh_Doddikalu_Resume.pdf" className="resume-download-card">
              <div className="resume-dl-icon">📄</div>
              <div>
                <div className="resume-dl-label">Download Resume</div>
                <div className="resume-dl-val">Mahesh_Doddikalu_Resume.pdf</div>
              </div>
            </a>
          </div>
        </div>
      </section>

      {/* SKILLS */}
      <section id="skills">
        <div className="sec-tag">technical-skills</div>
        <h2 className="sec-title">My <span className="hl">Tech Stack</span></h2>
        <div className="skills-grid">
          {SKILLS.map(({icon,title,cls,chips})=>(
            <div className="skill-card fade-up" key={title}>
              <div className="sk-icon">{icon}</div>
              <div className="sk-title">{title}</div>
              <div className="sk-chips">
                {chips.map(c=><span key={c} className={`sk-chip ${cls}`}>{c}</span>)}
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* PROJECTS — updated with real LinkedIn projects */}
      <section className="projects-section" id="projects">
        <div className="sec-tag">projects</div>
        <h2 className="sec-title">What I've <span className="hl">Built</span></h2>
        <div className="proj-grid">

          {/* Project 1 — Featured / Big */}
          <div className="proj-card big fade-up">
            <div className="proj-header">
              <div className="ph-bg"/>
              <div className="proj-emoji">🔧</div>
              <div className="proj-impact">30+ min → Under 2 min · Jul 2024 – Present</div>
            </div>
            <div className="proj-body">
              <div className="proj-tag">// plm-integration · windchill · production</div>
              <div className="proj-name">Windchill Assembly Reporting Tool</div>
              <div className="proj-desc">
                Built a Java + Spring Boot tool that connects to Windchill PLM APIs to auto-generate BOM-style assembly structure reports — eliminating a 100% manual extraction process used daily by engineering teams.
              </div>
              <ul className="proj-bullets">
                <li>Integrated Windchill REST APIs to extract &amp; transform nested assembly structure data at scale</li>
                <li>Reduced report generation time from <strong>30+ minutes to under 2 minutes</strong></li>
                <li>Adopted as the engineering team's standard daily tool — replaced all ad-hoc queries</li>
                <li>MySQL schema to persist report history and track generation jobs in real time</li>
              </ul>
              <div className="proj-stack">
